#include "controller.h"

#define MAX_TEMP_HISTORY 100U

static void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    // Handle malformed input and sensor timeout - always turn off heater
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT || 
        input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
        controller_set_safe_off(controller);
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = "STATE SAFE_OFF";
        output.changed = true;
        return output;
    }

    // Handle stale sensor data (>1000ms) - always turn off heater
    if (input.now_ms - controller->last_valid_sensor_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        controller_set_safe_off(controller);
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = "STATE SAFE_OFF";
        output.changed = true;
        return output;
    }

    // Handle temperature input
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        bool is_rising = false;

        // Check for early off condition: 50 <= TEMP <= 52 AND rising
        if (input.temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && 
            input.temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD &&
            input.temperature_c > controller->last_temperature_c) {
            is_rising = true;
        }

        // Apply control policy based on current temperature and state
        if (input.temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
            // TEMP < 47: turn heater on
            output.heater_on = true;
            output.state = CONTROLLER_STATE_HEATING;
            output.state_name = "STATE HEATING";
            output.changed = true;
        } else if (input.temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            // TEMP > 52: turn heater off
            output.heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = "STATE SAFE_OFF";
            output.changed = true;
        } else if (input.temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && 
                   input.temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            // 50 <= TEMP <= 52: hold previous state, but mark as HOLDING if rising
            output.heater_on = controller->heater_on;
            output.state = CONTROLLER_STATE_HOLDING;
            output.state_name = "STATE HOLDING";

            if (is_rising) {
                // Anticipatory heater-off - still counts as HOLDING, but heater will turn off soon
                output.heater_on = false;
                output.state = CONTROLLER_STATE_SAFE_OFF;
                output.state_name = "STATE SAFE_OFF";
                output.changed = true;
            } else {
                // Normal holding behavior
            }
        } else {
            // 47 <= TEMP < 50: hold previous safe actuator state
            output.heater_on = controller->heater_on;
            output.state = CONTROLLER_STATE_HOLDING;
            output.state_name = "STATE HOLDING";
            output.changed = false;
        }
    }

    // Update last temperature if we have a valid sensor
    if (controller->has_valid_sensor) {
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;
    }

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
        return "STATE SAFE_OFF";
    default:
        return "STATE UNKNOWN";
    }
}

