    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };

    if (controller == NULL) {
        return output;
    }

    // Handle malformed input and sensor timeout - always turn off heater
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT || 
        input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
        controller_set_safe_off(controller);
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = "STATE SAFE_OFF";
        output.changed = true;
        return output;
    }

    // Handle stale sensor data (>1000ms) - always turn off heater
    if (input.now_ms - controller->last_valid_sensor_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        controller_set_safe_off(controller);
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = "STATE SAFE_OFF";
        output.changed = true;
        return output;
    }

    // Handle temperature input
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        bool is_rising = false;

        // Check for early off condition: 50 <= TEMP <= 52 AND rising
        if (input.temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && 
            input.temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD &&
            input.temperature_c > controller->last_temperature_c) {
            is_rising = true;
        }

        // Apply control policy based on current temperature and state
        if (input.temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
            // TEMP < 47: turn heater on
            output.heater_on = true;
            output.state = CONTROLLER_STATE_HEATING;
            output.state_name = "STATE HEATING";
            output.changed = true;
        } else if (input.temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            // TEMP > 52: turn heater off
            output.heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = "STATE SAFE_OFF";
            output.changed = true;
        } else if (input.temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && 
