                output.heater_on = false;
                output.state = CONTROLLER_STATE_SAFE_OFF;
                output.state_name = "STATE SAFE_OFF";
                output.changed = true;
            } else {
                // Normal holding behavior
            }
        } else {
            // 47 <= TEMP < 50: hold previous safe actuator state
            output.heater_on = controller->heater_on;
            output.state = CONTROLLER_STATE_HOLDING;
            output.state_name = "STATE HOLDING";
            output.changed = false;
        }
    }

