typedef struct { protocol_input_kind_t kind; int temperature_c; } protocol_input_t;

bool protocol_parse_line(const char *line, protocol_input_t *input)
{
    if (!line || !input) return PROTOCOL_PARSE_IGNORED;

    size_t len = strlen(line);
    if (len > PROTOCOL_MAX_LINE_LENGTH) return PROTOCOL_PARSE_IGNORED;

    // Check for SENSOR_TIMEOUT
    if (strstr(line, "SENSOR_TIMEOUT")) {
        input->kind = PROTOCOL_INPUT_SENSOR_TIMEOUT;
        return PROTOCOL_PARSE_SENSOR_TIMEOUT;
    }

    // Check for temperature
    if (strstr(line, "TEMP ")) {
        int temp_c = atoi(line);
        if (temp_c >= -100 && temp_c <= 200) {
            input->kind = PROTOCOL_INPUT_TEMPERATURE;
            input->temperature_c = temp_c;
            return PROTOCOL_PARSE_TEMPERATURE;
        }
    }

    return PROTOCOL_PARSE_IGNORED;
}

bool protocol_serialize_act_heater(bool heater_on, char *buffer, size_t buffer_size)
{
    if (!buffer || !heater_on || buffer_size <= 0) return false;

    // Format: "ACT HEATER ON" or "ACT HEATER OFF"
    snprintf(buffer, buffer_size, "ACT HEATER %s", heater_on ? "ON" : "OFF");
    return true;
}

bool protocol_serialize_debug(const char *message, char *buffer, size_t buffer_size)
{
    if (!buffer || !message || buffer_size <= 0) return false;

    // Simple debug format: "MSG: <message>"
    snprintf(buffer, buffer_size, "MSG: %s", message);
    return true;
}

