static bool uart_read_frame(const char *line, uint32_t line_length)
{
    if (!uart_fd || !line || !line_length) return false;

    ssize_t nread = read(uart_fd, line, line_length);
    if (nread < 0) return false;
    if (nread == 0) return false;

    // Remove newline
    size_t len = strlen(line);
    while (len > 0 && (line[len-1] == '\r' || line[len-1] == '\n')) {
        line[--len] = '\0';
    }

    return true;
}

static bool uart_write_frame(const char *line)
{
    if (!uart_tx_fd || !line) return false;

    size_t len = strlen(line);
    // Remove newline
    while (len > 0 && (line[len-1] == '\r' || line[len-1] == '\n')) {
        line[--len] = '\0';
    }

    if (len > 0) {
        write(uart_tx_fd, line, len);
    }

    return true;
}

static bool uart_flush()
{
    if (!uart_tx_fd) return false;

    int flags = fcntl(uart_tx_fd, F_GETFL, 0);
    fcntl(uart_tx_fd, F_SETFL, flags | O_NONBLOCK);

    // Try to write and flush
    if (write(uart_tx_fd, "", 1) > 0) {
        return true;
    }

