    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    // Handle malformed input and sensor timeout - always turn off heater
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT || 
        input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
        controller_set_safe_off(controller);
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = "STATE SAFE_OFF";
        output.changed = true;
        return output;
    }

    // Handle stale sensor data (>1000ms) - always turn off heater
    if (input.now_ms - controller->last_valid_sensor_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        controller_set_safe_off(controller);
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = "STATE SAFE_OFF";
        output.changed = true;
        return output;
